body { cursor: none; }
.cursor-dot, .cursor-ring { position: fixed; top: 0; left: 0;
  border-radius: 50%; pointer-events: none; z-index: 9999; }
.cursor-dot { width: 8px; height: 8px; margin: -4px 0 0 -4px; background: #fff; }
.cursor-ring { width: 40px; height: 40px; margin: -20px 0 0 -20px;
  border: 1.5px solid rgba(255,255,255,0.6); }

var mx = 0, my = 0, rx = 0, ry = 0, scale = 1, target = 1;
document.addEventListener("mousemove", function(e){
  mx = e.clientX; my = e.clientY;
  target = e.target.closest("[data-hover]") ? 1.9 : 1;
});
(function frame(){
  rx += (mx - rx) * 0.15;            // 링만 lerp 0.15 지연
  ry += (my - ry) * 0.15;
  scale += (target - scale) * 0.18;
  dot.style.transform = "translate(" + mx + "px," + my + "px)";
  ring.style.transform = "translate(" + rx + "px," + ry + "px) scale(" + scale + ")";
  requestAnimationFrame(frame);
})();

body { cursor: none; isolation: isolate; }
.cursor-blend { position: fixed; top: 0; left: 0;
  width: 44px; height: 44px; margin: -22px 0 0 -22px;
  border-radius: 50%; background: #fff;
  mix-blend-mode: difference;
  pointer-events: none; z-index: 9999; }

var mx = 0, my = 0, cx = 0, cy = 0, s = 1, ts = 1;
document.addEventListener("mousemove", function(e){
  mx = e.clientX; my = e.clientY;
  ts = e.target.closest("[data-hover]") ? 2.4 : 1;   // hover 시 반전 영역 확대
});
(function frame(){
  cx += (mx - cx) * 0.18;
  cy += (my - cy) * 0.18;
  s += (ts - s) * 0.15;
  cur.style.transform = "translate(" + cx + "px," + cy + "px) scale(" + s + ")";
  requestAnimationFrame(frame);
})();

.view-core { display: flex; align-items: center; justify-content: center;
  transform: translate(-50%, -50%);
  width: 14px; height: 14px; border-radius: 999px; background: #fff;
  overflow: hidden;
  transition: width 0.25s cubic-bezier(0.2,0,0,1),
    height 0.25s cubic-bezier(0.2,0,0,1); }
.view-label { opacity: 0; transform: scale(0.6);
  transition: opacity 0.2s ease, transform 0.25s ease; }
.cursor-view.is-view .view-core { width: 78px; height: 34px; }
.cursor-view.is-view .view-label { opacity: 1; transform: scale(1); }

document.addEventListener("mousemove", function(e){
  mx = e.clientX; my = e.clientY;
  cur.classList.toggle("is-view", !!e.target.closest("[data-cursor=view]"));
});
(function frame(){
  cx += (mx - cx) * 0.16;
  cy += (my - cy) * 0.16;
  cur.style.transform = "translate(" + cx + "px," + cy + "px)";
  requestAnimationFrame(frame);
})();

.mag-btn { will-change: transform; }
.cursor-snap { position: fixed; top: 0; left: 0;
  width: 12px; height: 12px; margin: -6px 0 0 -6px;
  border-radius: 50%; background: #fff;
  pointer-events: none; z-index: 9999; }

var R = 110;                                  // 흡착 반경
function frame(){
  var dx = mx - center.x, dy = my - center.y;
  var d = Math.sqrt(dx * dx + dy * dy);
  var tx = mx, ty = my, gx = 0, gy = 0;
  if (d < R){
    var s = 1 - d / R;                        // 거리 기반 강도
    gx = dx * 0.3 * s; gy = dy * 0.3 * s;     // 버튼이 커서 쪽으로
    tx = mx - dx * 0.72 * s;                  // 커서가 버튼 중심으로
    ty = my - dy * 0.72 * s;
  }
  bx += (gx - bx) * 0.18; by += (gy - by) * 0.18;
  btn.style.transform = "translate(" + bx + "px," + by + "px)";
  cx += (tx - cx) * 0.2; cy += (ty - cy) * 0.2;
  cur.style.transform = "translate(" + cx + "px," + cy + "px)";
  requestAnimationFrame(frame);
}

.cursor-blob { position: fixed; top: 0; left: 0;
  width: 44px; height: 44px; margin: -22px 0 0 -22px;
  border-radius: 50%;
  background: radial-gradient(circle at 32% 32%, #c4b5fd, #7c3aed 72%);
  pointer-events: none; z-index: 9999; }

(function frame(){
  var nx = bx + (mx - bx) * 0.16;
  var ny = by + (my - by) * 0.16;
  var vx = nx - bx, vy = ny - by;          // 프레임 간 이동량 = 속도
  bx = nx; by = ny;
  var speed = Math.sqrt(vx * vx + vy * vy);
  if (speed > 0.3) angle = Math.atan2(vy, vx) * 180 / Math.PI;
  var s = Math.min(speed / 26, 0.5);       // stretch 클램프
  blob.style.transform = "translate(" + bx + "px," + by + "px)"
    + " rotate(" + angle + "deg)"
    + " scale(" + (1 + s) + "," + (1 - s * 0.55) + ")";
  requestAnimationFrame(frame);
})();

.ghost { position: fixed; top: 0; left: 0; border-radius: 50%;
  background: #fff; pointer-events: none; z-index: 9999; }
.g0 { width: 24px; height: 24px; margin: -12px 0 0 -12px; opacity: 1; }
.g1 { width: 19px; height: 19px; margin: -10px 0 0 -10px; opacity: 0.7; }
/* …g2~g4 점점 작고 옅게 */

var ks = [0.35, 0.24, 0.16, 0.105, 0.07];  // 머리→꼬리 lerp 계수
var pos = ghosts.map(function(){ return { x: 0, y: 0 }; });
(function frame(){
  for (var i = 0; i < ghosts.length; i++){
    pos[i].x += (mx - pos[i].x) * ks[i];
    pos[i].y += (my - pos[i].y) * ks[i];
    ghosts[i].style.transform =
      "translate(" + pos[i].x + "px," + pos[i].y + "px)";
  }
  requestAnimationFrame(frame);
})();

.cur-core { display: flex; align-items: center; justify-content: center;
  transform: translate(-50%, -50%);
  width: 14px; height: 14px; border-radius: 50%; background: #fff;
  transition: width 0.2s ease, height 0.2s ease; }
.cur-ic { position: absolute; opacity: 0; transform: scale(0.4);
  transition: opacity 0.16s ease, transform 0.2s ease; }
.cursor-icon.has-mode .cur-core { width: 42px; height: 42px; }
.cursor-icon.mode-drag .ic-drag { opacity: 1; transform: scale(1); }

var mode = "";
document.addEventListener("mousemove", function(e){
  mx = e.clientX; my = e.clientY;
  var z = e.target.closest("[data-cursor]");
  var m = z ? z.getAttribute("data-cursor") : "";
  if (m !== mode){                            // 변경 시에만 클래스 스왑
    mode = m;
    cur.className = "cursor-icon" + (m ? " has-mode mode-" + m : "");
  }
});

.thumb-card { position: absolute; left: 22px; top: -44px;
  width: 124px; height: 88px; border-radius: 10px; overflow: hidden;
  transform: scale(0) rotate(-8deg); transform-origin: 0 70%;
  transition: transform 0.28s cubic-bezier(0.34,1.56,0.64,1); }
.cursor-thumb.is-show .thumb-card { transform: scale(1) rotate(-6deg); }
.thumb-art { position: absolute; inset: 0; opacity: 0;
  transition: opacity 0.2s ease; }
.thumb-art.on { opacity: 1; }

document.addEventListener("mousemove", function(e){
  mx = e.clientX; my = e.clientY;
  var row = e.target.closest("[data-thumb]");
  if (row){
    var idx = parseInt(row.getAttribute("data-thumb"), 10);
    cur.classList.add("is-show");
    arts.forEach(function(a, i){ a.classList.toggle("on", i === idx); });
  } else {
    cur.classList.remove("is-show");
  }
});
// rAF: lerp 0.14 + 수평 속도 기반 tilt(±8°)

.trail-item { position: absolute; top: 0; left: 0;
  width: 84px; height: 112px; margin: -56px 0 0 -42px;
  border-radius: 12px; opacity: 0; }
.trail-item.live {
  animation: trail-pop 0.9s cubic-bezier(0.22,0.61,0.36,1) forwards; }
@keyframes trail-pop {
  0% { opacity: 0; transform: scale(0.5) rotate(var(--tilt)); }
  18% { opacity: 1; }
  100% { opacity: 0; transform: scale(1.08) translateY(-26px) rotate(var(--tilt)); }
}

var acc = 0, spawnCount = 0;
document.addEventListener("mousemove", function(e){
  acc += Math.sqrt(Math.pow(e.clientX - lastX, 2) + Math.pow(e.clientY - lastY, 2));
  lastX = e.clientX; lastY = e.clientY;
  if (acc >= 80){                              // 80px마다 스폰
    acc = 0;
    var el = items[spawnCount % items.length]; // 풀 순환 재사용
    el.className = "trail-item trail-g" + (spawnCount % 4);
    el.style.left = lastX + "px";
    el.style.top = lastY + "px";
    void el.offsetWidth;                       // 애니메이션 리셋
    el.classList.add("live");
    spawnCount++;
  }
});

.hold-svg { position: absolute; left: -28px; top: -28px; }
.hold-core { transition: transform 0.2s ease, background 0.2s ease; }
.cursor-hold.is-done .hold-core {
  transform: scale(2.4); background: #34d399; }
.hold-btn.is-confirmed {
  background: #34d399; border-color: #34d399; color: #052e1b; }

var C = 150.8;                                // 2πr (r=24)
var holding = false, progress = 0, last = Date.now();
stage.addEventListener("pointerdown", function(){ holding = true; });
window.addEventListener("pointerup", function(){ holding = false; });
(function frame(){
  var now = Date.now(), dt = Math.min(64, now - last);
  last = now;
  progress += holding ? dt / 900 : -dt / 500;  // 홀드 900ms / 되감기 500ms
  progress = Math.max(0, Math.min(1, progress));
  fill.style.strokeDashoffset = C * (1 - progress);
  if (progress >= 1) confirmAction();          // 게이지 완주 → 확정
  requestAnimationFrame(frame);
})();
